-- migrations/019_sales_templates_kz.sql
-- Волна 2 продажных шаблонов: 8 русских на жёсткое закрытие + 12 казахских.
-- Плюс раскладка шаблонов волны 1 по новым категориям (spin/objection/close),
-- чтобы панель «Шаблоны» в чате группировалась, а не была плоской свалкой.
--
-- !!! ВНИМАНИЕ !!! ЭТА МИГРАЦИЯ НЕ ПРИМЕНЕНА АВТОМАТИЧЕСКИ.
-- !!! Выполнить в Supabase → SQL Editor. Идемпотентна: on conflict do nothing
-- !!! + update по trigger. Повторный запуск ничего не сломает.
--
-- E'' обязателен: в обычных кавычках Postgres понимает \n буквально (см. 005).

insert into wa_quick_replies (trigger, title, body, category, sort_order) values
  (E'/либо', E'21. Либо да, либо нет (снять «висяк»)', E'{{имя}}, скажу как есть 🙂\n\nМы с вами посчитали, вы по цифрам проходите. Дальше только два варианта:\n\n1️⃣ Работаем — я сажусь за заявку, и через 2-4 недели вы с ключами\n2️⃣ Не работаем — я закрываю вашу заявку и не отвлекаю больше\n\nОба варианта нормальные. Плохой только третий — когда всё зависает на месяцы, а квартира дорожает.\n\nКакой из двух?', E'close', 31),
  (E'/итог', E'22. Резюмирующее закрытие', E'{{имя}}, давайте подведу итог 👇\n\nВы хотели: свою квартиру, без переплаты и без беготни по банкам.\nМы выяснили: по доходу вы проходите, стоп-факторов нет.\nЯ предлагаю: беру заявку, готовлю документы, подаю в банк, где шанс выше, и веду до выдачи денег.\n\nВсё, что осталось — ваше решение. Стартуем?', E'close', 32),
  (E'/ценабездействия', E'23. Сколько стоит «подождать»', E'{{имя}}, посчитаем цену ожидания 👇\n\nПока вы думаете, вы платите за аренду — эти деньги уходят чужому человеку и не возвращаются. За полгода это ощутимая сумма.\n\nПлюс квартиры не дешевеют. Та же квартира через полгода стоит дороже, а значит и первоначальный взнос нужен больше.\n\nОжидание — это тоже решение. Просто оно платное.\n\nМожет, начнём?', E'close', 33),
  (E'/рассрочка', E'24. «Дорого» → рассрочка оплаты услуги', E'{{имя}}, если вопрос только в сумме сразу — это решаемо 🤝\n\nОплату наших услуг можно разбить на 2-6 месяцев. Часть удерживается из зарплаты, часть вносите сами — я посчитаю вам точные цифры на любой срок: сколько внесёте, сколько удержится, сколько останется на карте.\n\nНа какой срок удобно разбить — 3 месяца или 6?', E'objection', 34),
  (E'/конкурент', E'25. «Другой брокер дешевле»', E'{{имя}}, честный ответ: дешевле всегда найдётся 👌\n\nВопрос один — что входит в цену. Спросите у них:\n• поднимают ли кредитную историю ДО подачи или подают наугад\n• сколько банков сравнивают или несут в один знакомый\n• ведут ли до выдачи денег или бросают после одобрения\n\nЕсли у них это есть и дешевле — берите, я серьёзно. Если нет — вы платите не за услугу, а за лотерею.', E'objection', 35),
  (E'/потом', E'26. «Давайте потом / после праздников»', E'{{имя}}, понимаю 👍\n\nТолько «потом» в ипотеке дорожает: ставки пересматривают, цены растут, а очередь в банках после праздников всегда длиннее.\n\nПредлагаю так: подготовку начнём сейчас — это ничего не стоит и ни к чему не обязывает. Разберу историю, посчитаю. К моменту, когда вы будете готовы, всё уже будет собрано, и вы не потеряете месяц.\n\nИдёт?', E'objection', 36),
  (E'/недоверие', E'27. «Вас много, все обещают»', E'{{имя}}, справедливо — обещают многие 🤷\n\nПоэтому предлагаю не обещания, а проверку: дайте мне вашу ситуацию, я подниму историю и назову реальные шансы. Бесплатно.\n\nНе понравится, как я работаю — просто не продолжим, вы ничего не теряете.\n\nПо-моему, честнее любых слов. Согласны?', E'objection', 37),
  (E'/финал', E'28. Финальный дожим перед закрытием лида', E'{{имя}}, пишу последний раз, чтобы не быть навязчивым 🙏\n\nВаша заявка у меня всё ещё открыта, цифры готовы. Если решили не сейчас — просто напишите «не сейчас», я закрою и больше не побеспокою.\n\nЕсли актуально — одно слово, и продолжаем с того же места.\n\nВ любом случае удачи вам с квартирой 🔑', E'close', 38),
  (E'/сәлем', E'🇰🇿 Алғашқы байланыс', E'Сәлеметсіз бе, {{имя}}! 👋\nМенің атым — {{менеджер}}, ипотека бойынша маманыңыз.\n\nБанкке өтінім бермес БҰРЫН қай бағдарлама сізге келетінін және қандай сомаға шынымен өтетініңізді есептеп беремін.\n\nАйтыңызшы: пәтерді өзіңізге аласыз ба? Қай қалада қарап жүрсіз?', E'kz', 41),
  (E'/жағдай', E'🇰🇿 Жағдайды анықтау', E'{{имя}}, дәл есептеу үшін 4 нәрсені айтыңызшы 👇\n\n1️⃣ Пәтердің шамамен құны қанша?\n2️⃣ Бастапқы жарнаға қанша сала аласыз?\n3️⃣ Ресми табысыңыз бар ма? Зейнетақы аударымдары түсе ме?\n4️⃣ Қолданыстағы несие немесе бөліп төлеу бар ма?\n\nЖауап берсеңіз — бүгін-ақ есеп жіберемін.', E'kz', 42),
  (E'/мәселе', E'🇰🇿 Мәселені ашу', E'{{имя}}, мәмілеге шығуға қазір не кедергі болып тұр?\n\nКөбіне үшеудің бірі:\n• қолданыстағы несиелер салдарынан банк соманы қысқартады\n• бастапқы жарна жетпейді\n• табыс ресми расталмайды\n\nСізде қайсысы? Талқылайық — әрқайсысының шешімі бар.', E'kz', 43),
  (E'/салдары', E'🇰🇿 Әрекетсіздіктің бағасы', E'{{имя}}, әдетте былай болады 👇\n\nБанктің бас тартуы жоғалмайды — ол несиелік тарихыңызда қалады. Қатарынан үш-төрт бас тарту болса, келесі банк сізге бастапқыдан да нашар қарайды.\n\nОның үстіне қайта беруге 2-3 апта кетеді. Ұнаған пәтер сол уақытта басқаға кетеді.\n\nТарихыңызбен тәуекел етесіз бе? Әлде алдымен қайда өтетініңізді нақты көрейік пе?', E'kz', 44),
  (E'/пайда', E'🇰🇿 Пайданы көрсету', E'{{имя}}, дұрыс түсінемін бе: қай банк мақұлдайтынын және қанша сома беретінін алдын ала білсеңіз — бас тартуларға айлап уақыт жоғалтпай, мәмілеге тезірек шығар едіңіз ғой?\n\nБіз дәл осыны істейміз: алдымен есептеп, тарихты тексереміз, содан кейін өтетін жеріңізге ғана береміз.\n\nБұл сізге қаншалықты өзекті?', E'kz', 45),
  (E'/бастарту', E'🇰🇿 Банк бас тартты', E'{{имя}}, бас тарту — үкім емес, диагноз 🩺\n\nБанкте әрқашан нақты себеп болады: несиелік жүктеме, бұрынғы мерзімі өткен төлемдер, өтіл, расталмаған табыс. Оны сізге айтпайды.\n\nСебеп табылмайынша — келесі өтінім де сол жаққа кетеді.\n\nНесиелік тарихыңызды көтеріп, нағыз себебін табайық. Сонда көзді жұмып бермейміз.', E'kz', 46),
  (E'/қымбат', E'🇰🇿 Қарсылық: «қымбат»', E'{{имя}}, түсінемін 👍 Сандармен сөйлесейік.\n\nБіздің қызмет — бір реттік. Ипотекадағы қате — 15-25 жылға.\n\n20 млн ₸ несиеде мөлшерлеменің 1% айырмасы — жылына жүздеген мың теңге артық төлем. Банкті немесе бағдарламаны қате таңдасаңыз — сол айырманы бүкіл мерзім бойы төлейсіз.\n\nБіз бағдарламаны дұрыс таңдаудың өзінде-ақ ақталамыз. Есебіңізден нақты көрсетейін бе?', E'kz', 47),
  (E'/ойланам', E'🇰🇿 Қарсылық: «ойланайын»', E'{{имя}}, әрине, ойланыңыз 👌\n\nТек ашық айтыңызшы, мен болжаммен отырмайын: ақпарат жетпей ме, қызмет бағасы келмей ме, әлде қазір уақыты емес пе?\n\nСандар жетпесе — есеп жіберемін, нақты нәрсеге қарап ойланасыз.', E'kz', 48),
  (E'/өзім', E'🇰🇿 Қарсылық: «өзім барамын»', E'{{имя}}, әрине, баруға болады — кейде жетеді де 👌\n\nБір ғана нюанс: банкте сізге сол банктің бағдарламаларын ғана көрсетеді. Несие менеджері сізді көршілердің шарттарымен салыстырмайды — бұл оның жұмысы емес.\n\nБіз барлық банкті бірден қараймыз және мүмкіндік жоғары, төлем төмен жерге береміз.\n\nБанкте болып қайттыңыз ба? Не айтқанын жазыңыз — тегін талдап беремін.', E'kz', 49),
  (E'/кепілдік', E'🇰🇿 Қарсылық: «кепілдік бересіз бе?»', E'{{имя}}, ашығын айтайын: мақұлдауға ешкім кепілдік бере алмайды — шешім әрқашан банкте. 100% уәде берген адам — алдап отыр 🚫\n\nБіз неге кепілдік береміз:\n• тарихыңызды талдап, өтінім бермес бұрын нақты мүмкіндігіңізді айтамыз\n• мүмкіндік жоғары банкке береміз\n• көзді жұмып бас тарту жинауға жол бермейміз\n\nСандар бойынша өтпесеңіз — тура айтамын, жұмысқа алмаймын. Екеумізге де адал болғаны.', E'kz', 50),
  (E'/құндылық', E'🇰🇿 Шартқа не кіреді', E'{{имя}}, шарт бойынша не аласыз 👇\n\n✅ Несиелік тарих пен зейнетақы аударымдарын талдау — кедергілерді табамыз\n✅ Бір емес, барлық қолайлы бағдарлама бойынша есеп\n✅ Жағдайыңызға сай банкті таңдау\n✅ Құжаттарды дайындау және өтінім беру\n✅ Ақша алғанға дейін сүйемелдеу: бағалау, нотариус, тіркеу\n✅ Әр қадамда байланыстағы жеке маманыңыз\n\nНәтижеге жұмыс істейміз: сіз ақша аласыз — біз өзімізді аламыз.', E'kz', 51),
  (E'/шарт', E'🇰🇿 Шартқа шақыру', E'{{имя}}, сандар бойынша өтесіз ✅ Бекітіп, бастауды ұсынамын.\n\nШартқа қол қоямыз — мен бірден өтініміңізге отырамын: тарих, құжаттар, банкке беру.\n\nШартқа онлайн қол қоямыз, ешқайда баруға керегі жоқ. Сомасы — {{сумма}} ₸.\n\nШартты танысуға жіберейін бе?', E'kz', 52)
on conflict (trigger) do nothing;

-- Категории волны 1 → новые группы
update wa_quick_replies set category = 'greeting' where trigger = E'/контакт';
update wa_quick_replies set category = 'spin' where trigger = E'/ситуация';
update wa_quick_replies set category = 'spin' where trigger = E'/проблема';
update wa_quick_replies set category = 'spin' where trigger = E'/последствия';
update wa_quick_replies set category = 'spin' where trigger = E'/выгода';
update wa_quick_replies set category = 'rejection' where trigger = E'/боль';
update wa_quick_replies set category = 'objection' where trigger = E'/самбанк';
update wa_quick_replies set category = 'objection' where trigger = E'/дорого';
update wa_quick_replies set category = 'objection' where trigger = E'/зачемвы';
update wa_quick_replies set category = 'objection' where trigger = E'/подумаю';
update wa_quick_replies set category = 'objection' where trigger = E'/гарантия';
update wa_quick_replies set category = 'objection' where trigger = E'/супруга';
update wa_quick_replies set category = 'general' where trigger = E'/кейс';
update wa_quick_replies set category = 'close' where trigger = E'/ценность';
update wa_quick_replies set category = 'close' where trigger = E'/договор';
update wa_quick_replies set category = 'close' where trigger = E'/дожим';
update wa_quick_replies set category = 'status' where trigger = E'/молчание';
update wa_quick_replies set category = 'close' where trigger = E'/рынок';
